\chapter{The sheaf of relative differentials}
\label{chap:differentials}

This chapter develops the sheaf of relative K\"ahler differentials $\Omega_{X/S}$ of a morphism of schemes $X \to S$, starting from the ring-theoretic K\"ahler differential module $\Omega_{B/A}$ already available in Mathlib. The output is a quasi-coherent sheaf of $\struct{X}$-modules characterised by its restriction to affine opens: for any affine open $V = \Spec B \subseteq X$ lying over an affine open $U = \Spec A \subseteq S$, the sections satisfy
\[
  \Omega_{X/S}(V) \;=\; \Omega_{B/A}.
\]

The downstream role of this chapter is twofold. First, the smoothness hypothesis on the curve $C \to \Spec k$ that appears in the Jacobian definition and the Abel--Jacobi map amounts to the condition that $\Omega_{C/k}$ is locally free of rank one; this characterisation is what unlocks the dimension computation $g(C) = \dim_k H^0(C, \Omega_{C/k}) = \dim_k H^1(C, \struct{C})$. Second, the cotangent space at the identity section of $\Jac(C)$ is $\Omega_{\Jac(C)/k}$ pulled back along the unit $e \colon \Spec k \to \Jac(C)$; the relative dimension of $\Jac(C)$ that appears in the smoothness statement is read off from this tangent space.

\section{The relative cotangent sheaf}

\begin{definition}[Relative cotangent presheaf of a morphism]
  \label{def:relative_kaehler_presheaf}
  \lean{AlgebraicGeometry.Scheme.relativeDifferentialsPresheaf}
  Let $f \colon X \to S$ be a morphism of schemes. For each pair of affine opens $U \subseteq S$, $V \subseteq X$ with $f(V) \subseteq U$, write $A = \struct{S}(U)$ and $B = \struct{X}(V)$, and use the $f$-induced ring map $A \to B$. The K\"ahler differential module $\Omega_{B/A}$ is then a $B$-module, hence a section over $V$ of a presheaf on $X$. The collection of these modules, together with the natural restriction maps along inclusions of affine opens, defines a presheaf of $\struct{X}$-modules on $X$.
\end{definition}

\begin{theorem}[Sheaf condition for $\Omega_{X/S}$]
  \label{thm:relative_kaehler_isSheaf}
  \lean{AlgebraicGeometry.Scheme.relativeDifferentialsPresheaf_isSheaf}
  \uses{def:relative_kaehler_presheaf}
  The relative cotangent presheaf is a sheaf in the Zariski topology on $X$. The proof reduces to the sheaf condition on the basis of affine basic opens, where it is the localisation compatibility $\Omega_{B[1/f]/A} \cong \Omega_{B/A} \otimes_B B[1/f]$ of the K\"ahler differential module; descent from a basis to all opens is standard.
\end{theorem}

\begin{definition}[Relative cotangent sheaf $\Omega_{X/S}$]
  \label{def:relative_kaehler_sheaf}
  \lean{AlgebraicGeometry.Scheme.relativeDifferentials}
  \uses{def:relative_kaehler_presheaf, thm:relative_kaehler_isSheaf}
  The sheaf of $\struct{X}$-modules associated with the relative cotangent presheaf is the \emph{sheaf of relative differentials} $\Omega_{X/S}$. It is quasi-coherent.
\end{definition}

\begin{remark}[Comparison with Mathlib's ring-level $\Omega_{B/A}$]
  \label{rem:kahler_compatibility}
  Mathlib provides the ring-theoretic K\"ahler differential module $\Omega_{B/A}$ together with the universal derivation $\mathrm{d} \colon B \to \Omega_{B/A}$. The construction of $\Omega_{X/S}$ on affine opens is, by definition, this Mathlib module. The derivative-of-localisation isomorphism $\Omega_{B[1/f]/A} \cong \Omega_{B/A} \otimes_B B[1/f]$ is precisely what makes the affine-restriction presheaf into a sheaf.
\end{remark}

